import java.util.function.*;
public class MethodRefs {
    static int triple(int x) { return x * 3; }
    public static void main(String[] args) {
        IntUnaryOperator op1 = MethodRefs::triple;   // static ref
        IntUnaryOperator op2 = Math::abs;            // static ref
        IntUnaryOperator op3 = Integer::bitCount;    // static ref to Integer
        System.out.println(op1.applyAsInt(4));
        System.out.println(op2.applyAsInt(-7));
        System.out.println(op3.applyAsInt(0b1010));
    }
}
